def test_tc_gw_s03_001_doorrl_closed_to_open(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    assert decode_door_rl(msgs[-1]) == 1

def test_tc_gw_s03_002_doorrl_open_to_closed(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    assert decode_door_rl(msgs[-1]) == 0

def test_tc_gw_s03_003_doorrl_stays_open(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    for msg in msgs:
        assert decode_door_rl(msg) == 1

