def test_tc_gw_s03_005_doorrl_immediate(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    assert decode_door_rl(msgs[0]) in (0, 1)

def test_tc_gw_s03_006_doorrl_deterministic(can_bus):
    msgs = collect_messages(can_bus, MSG_ID_BODY_STATUS, CAPTURE_TIME)
    reference = decode_door_rl(msgs[0])
    for msg in msgs:
        assert decode_door_rl(msg) == reference

